from flask import Flask
from flask_graphql import GraphQLView
import graphene
from graphene import ObjectType, String, Int, List, Field, Schema, NonNull
from flask_cors import CORS
import os
from datetime import datetime

# Mock data
PRODUCTS = [
    {"id": 1, "name": "Laptop", "price": 999.99, "category_id": 1, "description": "High performance laptop"},
    {"id": 2, "name": "Smartphone", "price": 599.99, "category_id": 2, "description": "Latest smartphone"},
    {"id": 3, "name": "Headphones", "price": 199.99, "category_id": 3, "description": "Wireless headphones"}
]

CATEGORIES = [
    {"id": 1, "name": "Electronics"},
    {"id": 2, "name": "Mobile"},
    {"id": 3, "name": "Audio"}
]

REVIEWS = [
    {"id": 1, "product_id": 1, "user": "Alice", "rating": 5, "comment": "Great laptop!"},
    {"id": 2, "product_id": 1, "user": "Bob", "rating": 4, "comment": "Good performance"},
    {"id": 3, "product_id": 2, "user": "Charlie", "rating": 5, "comment": "Amazing phone!"}
]

class Product(ObjectType):
    id = Int()
    name = String()
    price = Float()
    category_id = Int()
    description = String()

class Category(ObjectType):
    id = Int()
    name = String()

class Review(ObjectType):
    id = Int()
    product_id = Int()
    user = String()
    rating = Int()
    comment = String()

class Query(ObjectType):
    products = List(Product)
    categories = List(Category)
    reviews = List(Review)
    product_by_id = Field(Product, id=NonNull(Int))
    category_by_id = Field(Category, id=NonNull(Int))
    reviews_by_product = List(Review, product_id=NonNull(Int))
    
    def resolve_products(self, info):
        return PRODUCTS
    
    def resolve_categories(self, info):
        return CATEGORIES
    
    def resolve_reviews(self, info):
        return REVIEWS
    
    def resolve_product_by_id(self, info, id):
        for product in PRODUCTS:
            if product["id"] == id:
                return product
        return None
    
    def resolve_category_by_id(self, info, id):
        for category in CATEGORIES:
            if category["id"] == id:
                return category
        return None
    
    def resolve_reviews_by_product(self, info, product_id):
        return [review for review in REVIEWS if review["product_id"] == product_id]

schema = Schema(query=Query)

app = Flask(__name__)
CORS(app)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True,
        introspection=True
    )
)

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)